var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오늘 퇴원한다고 들었네. 몸은 괜찮나?","JPN":"今日退院すると聞いたが。調子はどうかね？","ENG":"I heard you're being discharged today. How are you feeling?","TWN":"聽說你今天出院了。怎麼樣，還好嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"물론이죠. 다른 분들이 대신 바쁜 덕에 편히 쉰 걸요.","JPN":"おかげさまで。他の方々が代わりによく動いてくださって、ゆっくり休めました。","ENG":"Sure. I got to rest comfortably because others were busy instead.","TWN":"嗯嗯，多虧了別人幫我頂著，我才能這麼悠閒地休息。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"소대원들은 좀 더 회복이 필요할 것 같아서, 저 먼저 복귀하기로 했습니다.","JPN":"他の小隊員はもう少し回復してからということなので、私だけでも先に復帰することにしました。","ENG":"Since other squad members needed more time to recover, I decided to return to work first.","TWN":"因為其他小隊成員還需要更多時間恢復，所以我決定先歸隊了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"필요하면 연차라도 써서 쉬게나. 부사장도 연말 휴가는 못 막을 테니.","JPN":"必要だと思ったら年休でも使いたまえ。さすがの副社長も許可せざるを得ないだろう。","ENG":"If necessary, feel free to use your year-end vacation. Even the Vice President won't object to that.","TWN":"如果覺得太累，可以在年底休假。副總不會拒絕的。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"후후, 그렇게 걱정해주시니 마음만으로도 감사하네요.","JPN":"ふふ、そうやって心配してもらえるなんて、心だけでもありがたいですね。","ENG":"Haha, thank you for caring.","TWN":"呵呵，謝謝你的關心。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그렇지만 귀한 <color=#ffd34c>청춘</color>을 병원에서 낭비하는 건 아깝잖아요? 놀 시간에 경력이라도 쌓아야죠.","JPN":"ですが、貴重な<color=#ffd34c>青春</color>を病院で無駄遣いするのはもったいないでしょう？　遊ぶ時間があるなら経歴を積んでおかないと。","ENG":"But isn't it a bit of a waste to spend my precious <color=#ffd34c>youth</color> in a hospital? I want to build my career, even just a little more.","TWN":"但是把寶貴的[青春]都花在醫院裡有點可惜吧？我想多積累一些職業經驗。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"경력이라…….","JPN":"経歴か……","ENG":"You say career…","TWN":"……原來如此。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 내 생각에 당분간 커리어가 될 만한 일거리는 없을 것 같군.","JPN":"すまないが、しばらく経歴に役立ちそうな仕事は予定にないのでね。","ENG":"But I don't think there will be any tasks that could boost your career for now.","TWN":"很抱歉，暫時沒有能積累經驗的工作了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"대신 괜찮다면 신참 카운터 한 명의 교육을 자네에게 맡기고 싶은데.","JPN":"代わりと言ってはなんだか、君には1人の新人カウンターの教育を任せたい。","ENG":"Instead, I'd like to assign you the task of training a rookie Counter if you're okay.","TWN":"但我打算把一個新手制裁者的培訓任務交給你。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네? 제가 신입 교육을요?","JPN":"はい？　私が教育を、ですか？　新人の？","ENG":"Huh? Training a rookie? Me? ","TWN":"嗯？我來嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아직 정식 사원은 아니지만, 한 사람 몫을 해낼 수 있도록 부탁하지.","JPN":"まだ正社員ではないのだが、一人前のカウンターになれるように指導を頼む。","ENG":"She's not officially an employee yet, but I'm counting on you to help her become competent.","TWN":"雖然還不是正式員工，但希望她能勝任一個人的工作。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"특히 사회생활 쪽으로 말이야.","JPN":"特に社会生活の面で。","ENG":"Especially in terms of social skills.","TWN":"特別是在社會生活這方面。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내 개인적인 부탁이니, 부담스럽다면 미리 말하게.","JPN":"私からの個人的な頼みでね。負担になるようなら先に言ってくれ。","ENG":"It's a personal favor of mine. If teaching feels too burdensome, let me know in advance.","TWN":"這是我個人的請求。如果覺得有壓力，可以告訴我。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아핫, 그러니까 사장님의 개인적인 부탁이란 말씀이시죠?","JPN":"ふふ、社長の個人的な頼み、ということですね？","ENG":"Haha, so it is a personal favor from Boss…?","TWN":"呵呵，老闆的私人請求啊……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"마침 잘 됐네요. 간만의 복귀인데, 혼자만 어색하진 않겠어요.","JPN":"ちょうどよかったです。久しぶりの復帰で私だけ気まずくなることはなさそうです。","ENG":"This works out well. As I'm reporting back after a long time, it's good not to be awkward alone.","TWN":"也正好。好久沒回來，能有個人陪著就不會那麼尷尬了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"고맙네. 서윤 양만 믿지.","JPN":"ありがとう。ではシズカ君を信じて任せることにしよう。","ENG":"Thank you. I'll leave it all in your hands, Seo Yoon.","TWN":"謝謝。那就麻煩你多費心了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"맡겨만 주세요. 늘 그래왔던 대로.","JPN":"お任せください。いつものように。","ENG":"Leave it to me. Just like always.","TWN":"好的，沒問題。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"쓸데없는 소릴 했네. <color=#ffd34c>청춘</color>을 낭비하고 싶지 않다니.","JPN":"余計なことを言っちゃったわね。<color=#ffd34c>青春</color>を無駄遣いしたくないだなんて。","ENG":"That was a pointless thing to say. <color=#ffd34c>Youth</color>, huh?","TWN":"我在胡說八道什麼，什麼[青春]啊。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"청춘답게 살아본 적도 없는데, 왜 그런 표현이 튀어나온 거람?","JPN":"青春っぽいことなんてしたこともないくせに、何であんなこと言っちゃったんだろう？","ENG":"I've never even experienced a time like that, so why did I say something like that?","TWN":"明明沒有經歷過那樣的時代，為什麼會說出那樣的話呢？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"신입 교관이라…","JPN":"教官の仕事か……","ENG":"Instructor for a rookie...","TWN":"教官的角色啊……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"적어도 심심할 걱정은 없겠어.","JPN":"少なくとも退屈はしなそうね。","ENG":"Well, I won't be bored, at least.","TWN":"至少不會無聊了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아직 도착을 안 했다고요?","JPN":"まだ来ていないんですか？","ENG":"She still hasn't arrived yet?","TWN":"還沒到嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네… 시내버스로 온다고 해서 한 시간째 정류장에서 기다리는데, 안 보이네요.","JPN":"はい……市内バスで来ると聞いていたのでバス停でもう1時間も待っていますが、姿が見えません。","ENG":"No... She said she'd come by city bus, but I've been waiting at the stop for an hour and haven't seen her.","TWN":"嗯……說是要坐公車來，我已經在車站等了一個小時了，還沒看到人。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"연락처도 없어서 아무래도 실종 신고를 하는 편이 좋을 것 같아요.","JPN":"連絡先もなくて、困っているんです。警察に通報した方がいいのでしょうか。","ENG":"She doesn't have a contact number. Should we consider filing a missing person report?","TWN":"沒有聯繫方式，而且年紀又小，要報警嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"부장님? 공항에서 회사로 오는 버스 노선은 하나라고 하셨죠?","JPN":"空港から会社までのバスは1本だけですよね？　部長。","ENG":"You mentioned there's just one bus route from the airport to the company, right?","TWN":"從機場到公司的公車線路只有一條，對吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"네? 그치만 전 여기서 창밖을 더 구경하고 싶은데요.","JPN":"え？　でも私はここで窓の外をもっと見ていたいんですけど。","ENG":"Huh? But I want to keep watching the view from the window here.","TWN":"嗯？可是我還想在車裡多看一會窗外的風景呢。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DRIVER_NPC_BUS_NULL","text":{"KOREA":"꼬마. 아까도 말했지만 승객은 반환점에서 전부 내려야 해.","JPN":"お嬢ちゃん。さっきも言ったが、乗客は折り返し地点で全員降りなければならないんだ。","ENG":"Hey, kid. Like I said earlier, all passengers have to get off at the turnaround point.","TWN":"小朋友，剛才也說過，乘客必須在終點站全部下車。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DRIVER_NPC_BUS_NULL","text":{"KOREA":"미안하지만 버스는 공짜로 움직이는 게 아니야. 돈을 더 내던가.","JPN":"悪いけどバスはタダで乗れるものじゃない。乗りたければ料金を払いな。","ENG":"Sorry, but buses don't run for free. Or you can pay more money.","TWN":"抱歉，公車可不是免費的。要麼多付點車費吧。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"그치만 지금은 돈이 없는데…","JPN":"でも、もうお金が……","ENG":"But I don't have any money left...","TWN":"可是我現在沒有錢……"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"…아!","JPN":"……あ！","ENG":"...Oh!","TWN":"……啊！"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L49_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"이거 가질래요? 쓰다듬으면 좋은 향이 나요.","JPN":"これ、あげますか？　なでなでするといい香りがしますよ？","ENG":"How about this? It smells really good.","TWN":"這個怎麼樣？夠嗎？"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DRIVER_NPC_BUS_NULL","text":{"KOREA":"꽃다발…?","JPN":"花束……？","ENG":"A bouquet...?","TWN":"手捧花……？"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DRIVER_NPC_BUS_NULL","text":{"KOREA":"나한테 꽃을 팔려는 거냐?","JPN":"今俺に花を売ろうってのか？","ENG":"Are you trying to sell me flowers?","TWN":"現在你是想賣花給我嗎？"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"음… 그러니까…","JPN":"うん……えっと……","ENG":"Uh... well...","TWN":"嗯……就是說……"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"잔돈은 필요 없어요!","JPN":"お釣りは大丈夫です！","ENG":"I don't need change!","TWN":"不用找零了。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L6_1","type":"dialog","speaker":"DRIVER_NPC_BUS_NULL","text":{"KOREA":"나 참, 잔돈은 무슨.","JPN":"まったく。お釣りも何もないだろうが。","ENG":"Change, huh?","TWN":"哈哈，還給你找零呢。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DRIVER_NPC_BUS_NULL","text":{"KOREA":"얼른 출발해야 하니까 장난 칠 거면 내려…","JPN":"はやく出発しないといけないから、ふざけたいんだったら降りてくれ……","ENG":"We're about to leave, so if you're just messing around, step off–","TWN":"現在要出發了，如果只想開玩笑的話就下車吧……"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"휴, 아직 출발 안 해서 다행이네.","JPN":"ふう、まだ出発していない、よかった。","ENG":"Phew, good thing it hasn't left yet.","TWN":"呼，還好還沒出發。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"두 사람이요.","JPN":"2人です。","ENG":"Two tickets, please.","TWN":"有兩個人。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DRIVER_NPC_BUS_NULL","text":{"KOREA":"둘? 아가씬 혼자인 것 같은데?","JPN":"2人？　お嬢さん、どう見ても1人だけど？","ENG":"Two? But it looks like you're alone, miss.","TWN":"嗯？小姐，你不是一個人嗎？"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"여기 있는 제 동생 몫까지요.","JPN":"ここにいる私の妹の分も含めてです。","ENG":"It's for my little sister here.","TWN":"加上我妹妹的。"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRIVER_NPC_BUS_NULL","text":{"KOREA":"이 꼬마가 아가씨 동생이었어?","JPN":"はぁ……？　あ、姉妹ってわけか？","ENG":"She's your sibling?","TWN":"什麼……？她是你的妹妹啊？"},"stage":{"bg":"MYEONGDONG","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"저기… 고맙습니다?","JPN":"あの……ありがとうございます？","ENG":"Um... Thank you?","TWN":"那個……謝謝姊姊？"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"고마워 할 필요 없어. 나중에 갚을 테니까.","JPN":"お礼はいらないわ。後で返してもらうから。","ENG":"No need to thank me. You'll pay it back eventually.","TWN":"不用謝，以後你會還我的。"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네가 코핀컴퍼니에 연수 오기로 했던 신입이지?","JPN":"あなたがコフィンカンパニーで研修を受けることになっていた新人よね？","ENG":"You're the rookie coming to train at Coffin Company, right?","TWN":"你是來科芬公司實習的新人吧？"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"앗, 아뇨.","JPN":"あっ、いいえ。","ENG":"Oh, no.","TWN":"不。"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_QM","text":{"KOREA":"제 이름은 신입이 아니라 솔로베라고 해요.","JPN":"私の名前は新人ではなくソロべーです。","ENG":"My name isn't rookie, it's Solovey.","TWN":"我不叫新人，我叫蘇羅薇。"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어머, 자의식이 강한 친구였구나.","JPN":"あら、自我が強い子ね。","ENG":"Oh, you've got a strong sense of self, huh?","TWN":"呵呵，自我意識還挺強的。"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런데 교통비로 쓸 돈이 없다니. 사장님께서 너한테 돈을 충분히 안 챙겨 준 거야?","JPN":"でも交通費がないなんて。社長からお金は十分貰ったんじゃないの？","ENG":"But no fare money? Did Boss not give you enough?","TWN":"但是你說沒有車費。是老闆沒有給你足夠的錢嗎？"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_QM","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아, 그 돈은 다른 사람한테 줬어요.","JPN":"あ、はい。そのお金は他の人にあげました。","ENG":"Oh, I gave the money to someone else.","TWN":"錢給了別人。"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"다른 사람? 누구?","JPN":"あげた？　誰に？","ENG":"Someone else? Who?","TWN":"給別人了？給誰了？"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"버스를 타기 전에 돈이 필요하다는 아이를 만났거든요.","JPN":"バスに乗る前に、お金が必要だという子に会ったんです。","ENG":"I ran into a child before getting on the bus.","TWN":"在巷子裡遇到了一個需要錢的孩子。"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"잠깐. 그렇다고 처음 본 애한테 돈을 다 줬단 말이야?","JPN":"待って。だからって、初めて会った子にお金を全部あげちゃったの？","ENG":"Wait. So you gave away all the money you had?","TWN":"所以你把所有的錢都給他了？"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니가 아픈 걸 고치려면 엄-청 비싼 약이 필요하대요.","JPN":"お母さんの病気を治すにはとーても高額の薬が必要だそうです。","ENG":"She said she needed to buy so expensive medicine to cure her mother's sickness.","TWN":"他說媽媽生病了，需要昂貴的藥才能治好。"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"소중한 사람이 아프면 슬프니까요. 그래서 줬어요.","JPN":"大切な人が苦しんでいたら悲しいですから。だからあげました。","ENG":"When someone precious to you is sick, it's sad. That's why I gave it to her.","TWN":"重要的人生病了會很難受的。所以都給他了。"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"비싼 약이라니. 뻔한 거짓말이잖아.","JPN":"高額の薬って……よくあるウソでしょう、それ。","ENG":"Expensive medicine...? That's such an obvious lie.","TWN":"說是去買藥……？根本是騙人的吧？"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런 거에 속을 정도로 분별력이 없는 거야?","JPN":"そんなのに騙されるほど判断力がないの？","ENG":"Are you really that gullible?","TWN":"你那麼容易上當受騙嗎？"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"거짓말인가요? 정말로 필요해보였는데.","JPN":"ウソ……なんですか？　とても切実に見えましたけど……","ENG":"It was a lie? But she really seemed to need it.","TWN":"那是……騙人的嗎？看起來真的很需要說。"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하아…","JPN":"はあ……","ENG":"*Sigh*","TWN":"哀哀……"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"사회생활을 가르치래서 어느 정돈가 했는데, 그 정도 레벨의 수법에 당할 줄이야.","JPN":"社会生活を教えろって言うからどのくらいなのかと思ったけど、そのレベルの詐欺にやられてしまうなんて。","ENG":"I was told to teach you social skills, but I wasn't sure where to start. But never expected you would fall for such a simple trick.","TWN":"老闆要我幫助你融入社會，我還以為你多少懂點，結果你真的什麼都不知道啊？"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"잘 들어. 사람의 겉모습이나 말만 듣고 쉽게 믿으면 안돼.","JPN":"いい？　人を見た目や言葉だけで簡単に信じてはいけないの。","ENG":"Listen carefully. You shouldn't easily trust people just based on their appearance or words.","TWN":"給我聽好了，不能輕易相信一個人的外表或言辭。"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"특히 도시에선 아무나 믿었다간 손해만 보게 될 거야.","JPN":"特に都市では信じる相手を間違えると大損するわよ。","ENG":"Especially in the city, trusting anyone too easily will only lead to losses.","TWN":"特別是在城市裡，隨便相信別人只會吃虧。"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"네! 이제 돈 함부로 안 줄게요!","JPN":"はい！　これからお金は簡単に人にあげたりしません！","ENG":"Got it! I won't give money away so easily anymore!","TWN":"好！以後我不會隨便給錢了！"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"지금은 한 푼도 없지만요…","JPN":"今は無一文ですが……","ENG":"Even though I don't have any right now...","TWN":"雖然現在我一毛錢都沒有……"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"괜찮아. 돈 벌러 온 거니까, 지금부터 열심히 모으면 되지.","JPN":"大丈夫。お金を稼ぐために来たんだから、これから頑張って働いて貯めればいいわ。","ENG":"It's fine. You came here to earn money, so work hard to save money from now on.","TWN":"沒關係。本來就是來賺錢的，從現在開始努力工作存錢就行了。"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하아… 카운터 기량부터 체크하려 했는데, 다른 쪽도 갈 길이 멀어 보이네.","JPN":"はあ…...カウンターの力量をチェックしようと思ってたのに、こっちの方も道のりが長そうね。","ENG":"*Sigh* I was planning to start by assessing your Counter ability, but it looks like there's a long way to go in other aspects too.","TWN":"本來還想先確認一下制裁者能力的，看來其他方面也還有很長的路要走啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그건 그렇고, 어쩌다 종점까지 버스에서 안 내린 거야? 깜빡 잠들기라도 했어?","JPN":"それより、何で終点までバスから降りなかったの？　うっかり眠ってしまった？","ENG":"Anyway, how did you end up staying on the bus until the last stop? Did you doze off?","TWN":"話說回來，你怎麼會坐到終點站都沒下車？是打瞌睡了嗎？"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아뇨? 이런 재밌는 건 처음 타봐서요.","JPN":"いいえ。こんなに楽しいものに乗るのは初めてなんです。","ENG":"No? It's my first time riding something this fun.","TWN":"我第一次坐這種東西。"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"창밖이 움직이는 게 너무 신기해서 시간 가는 줄 모르고 구경했어요.","JPN":"窓から見える風景の移り変わりがとても目新しくて、時間も忘れてずっと見ていました。","ENG":"The view outside the window was moving so captivatingly that I lost track of time.","TWN":"透過窗戶看建築後退很新奇，所以忘了時間。"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"계속 타려면 돈을 더 내야 할 줄은 몰랐지만요.","JPN":"ずっと乗るためにはお金が必要だとは知らなかったんです。","ENG":"I didn't know I'd have to pay more to keep riding, though.","TWN":"沒想到繼續坐還要加錢呢……"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"돈은 항상 갖고 있는 게 좋아. 도시에선 온갖 혜택을 누릴 수 있지만, 대부분에는 돈이 필요하거든.","JPN":"お金は常に持っていた方がいいわ。都市ではあらゆることを享受できるけど、ほとんどの場合はそこにお金が必要だから。","ENG":"It's always good to have money on you. In the city, you can enjoy all sorts of benefits, but most of them require money.","TWN":"隨時帶著錢是好的。在城市裡可以享受各種福利，但大多數情況下都需要錢。"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"지금까지 어떤 곳에서 지냈길래 버스 타는 법도 몰랐던 거니?","JPN":"バスの乗り方も知らないなんて、今までどんなところで住んでいたの？","ENG":"Where have you been living until now that you don't even know how to ride a bus?","TWN":"你之前都待在哪，連坐公車都不會？"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"전 정원에서 살았어요. 어머니랑 둘일 때도, 혼자일 때도.","JPN":"私は庭園で暮らしていました。お母さんと2人の時も、1人きりの時も。","ENG":"I lived in a garden. With Mother when it was the two of us, and even when I was alone.","TWN":"我以前一直住在花園裡。不管是和媽媽一起的時候，還是一個人的時候。"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"여긴 꽃과 나무는 별로 없지만, 커다란 집이 잔뜩 있어서 마음에 들어요.","JPN":"ここは花と木は少ないけど、大きな家がたくさんあって気に入りました。","ENG":"There aren't many flowers or trees here, but I like it because there are so many big houses.","TWN":"這裡雖然花草樹木不多，但有很多漂亮的房子，我很喜歡。"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"정원이라… 이제 막 도시에 상경한 시골 꼬마려나?","JPN":"庭園ね……田舎から都会に来たばかりの田舎娘ってこと？","ENG":"A garden...? So apparently she's a countryside kid who has just moved to the city?","TWN":"花園嗎……是剛剛進城的鄉下小孩嗎？"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"손이 많이 가겠지만, 어쩔 수 없지.","JPN":"手間はかかりそうだけど、頼まれた以上は仕方ない。","ENG":"She's going to take a lot of work, but I don't have a choice.","TWN":"感覺會很麻煩，但既然老闆都拜託我了，那也沒辦法。"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"난 오늘부터 널 돌보게 된 서윤이라고 해.","JPN":"私は今日からあなたを教えるアオイ・シズカ。","ENG":"I'm Seo Yoon. I'll be looking after you starting today.","TWN":"我叫徐芸，從今天起由我來負責你的實習培訓。"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네가 오게 될 코핀컴퍼니의 대선배이자, 사장님의 최측근 중 한 명이지.","JPN":"あなたが入社するコフィンカンパニーの大先輩であり、社長の最側近のうちの1人よ。","ENG":"I'm a veteran of Coffin Company, where you'll be training, and one of the Boss's closest associates.","TWN":"我是你即將加入的公司前輩，也是老闆身邊最親近的人之一。"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"와아…?","JPN":"わあ……？","ENG":"Wow...?","TWN":"哇啊…？"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"당분간 나랑 떨어지지 말고 같이 지내자. 널 혼자 두면 얼마를 쥐어줘도 금방 빈털터리가 될 테니까.","JPN":"しばらくは私と常に一緒に過ごしましょう。あなたを1人にしたら、いくら渡してもすぐ無一文になりそうだしね。","ENG":"For now, stick with me and don't wander off on your own. If I leave you alone, no matter how much money you're given, you'll end up broke in no time.","TWN":"接下來你就先跟著我。要是放你一個人，不管你口袋裡有多少錢，也很快就會花光的。"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"네! 그럼 꼭 붙어 다닐게요.","JPN":"はい！　では必ず一緒に付いていきます。","ENG":"Okay! I'll make sure to stay right by you.","TWN":"好的！我會緊緊跟著你的。"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런데, 어쩌다 이 회사로 오게 된 거야? 우리 사장님은 아무나 데려오는 분은 아닌데.","JPN":"それにしても、どうやってこの会社に来ることになったの？　うちの社長は誰でも連れてくる人ではないけど。","ENG":"By the way, how did you end up joining this company? Boss doesn't bring in just anyone.","TWN":"不過，你是怎麼到這家公司的？我們老闆可不是隨便帶人進來的。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"집이 없어서요. 회사로 가면 일도 배우고 머물 곳도 있대서 왔어요.","JPN":"私、もう住む家がないんです。でも会社に行けば仕事も教えてもらえるし、寝るところもあると聞いて来ました。","ENG":"I didn't have a home. I heard the company provides training and a place to stay, so I came here.","TWN":"因為我沒有家。聽說去公司可以學到東西，還有地方住，所以我來了。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"여기 오기 전엔 관리자 씨랑 식당이란 곳에서 돈까스를 같이 먹었는데, 엄청 맛있더라고요!","JPN":"ここに来る前は管理者さんと食堂という場所で一緒にとんかつを食べましたけど、とても美味しかったです！","ENG":"Before I got here, I ate pork cutlets with Mr. Administrator at somewhere called a restaurant. They were so tasty!","TWN":"來這裡之前，我們一起在餐廳吃了炸豬排，超好吃的！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"집이 없다고? 방금 전엔 어머니랑 같이 지낸다며?","JPN":"家がない？　さっきお母さんと一緒に暮らしたって言ってなかった？","ENG":"You don't have a home? Didn't you just say a moment ago that you live with your mother?","TWN":"沒有家？剛才不是說和媽媽一起住嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"啊……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머닌 6년 전에 돌아가셨어요.","JPN":"お母さんは亡くなりました。6年前に。","ENG":"Mother is gone 6 years ago.","TWN":"媽媽已經不在了。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"지금은 집마저 사라져서, 갈 곳이 없는 절 관리자 씨 동료가 이곳에 데려와줬거든요.","JPN":"今は家もなくなって、行き場のない私を管理者さんの仲間がここに連れてきてくれたんです。","ENG":"Now I lost my home too and have no place to go. So, Mr. Administrator's colleague brought me here.","TWN":"6年後家也沒了，無處可去的我被管理者先生的同事帶到了這裡。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"널 찾아서 데려 왔다고…?","JPN":"あなたを探して連れてきた……？","ENG":"You were searched for and brought here...?","TWN":"老闆去把你帶過來的？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"혹시 왜인지 알아? 사장님이 네 어머니랑 전부터 아는 사이였다거나…","JPN":"理由はわかるかな？　社長があなたのお母さんと前から知り合いだったとか……","ENG":"Do you happen to know why? Maybe Boss knew your mother from before or something...?","TWN":"你知道為什麼嗎？難道老闆和你媽媽以前就認識嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"맞아요! 관리자 씨랑 어머니는 동료였대요!","JPN":"そうです！　管理者さんとお母さんは仲間だったんですって！","ENG":"That's right! Mr. Administrator and Mother were colleagues!","TWN":"沒錯，管理者先生和媽媽是同事。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"제가 뱃속에 있을 때 관리자 씨가 떠났고, 두 분은 결국 다시 못 만났지만요.","JPN":"管理者さんは私がお母さんのおなかの中にいる時に行ってしまって、お2人は結局二度と会えなかったらしいんです。","ENG":"When Mother was pregnant with me, Mr. Administrator left her and they never met again.","TWN":"但是管理者先生在我還在媽媽肚子裡的時候，就把她丟在了花園裡離開了。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"응? 사장님이 네 어머닐 두고 떠났다고…?","JPN":"えっ？　社長があなたのお母さんを置いて行ってしまった……？","ENG":"What...? Boss left your mother…?","TWN":"嗯……？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L32_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"네, 그건 어머니의 선택이었어요. 관리자 씨는 해야 할 일이 많으니까. 방해되고 싶지 않았대요.","JPN":"はい、それはお母さんが選んだことでした。管理者さんはやるべきことが多いから。邪魔したくなかったって。","ENG":"It was Mother's decision. Mr. Administrator has a lot of things to do, so she didn't want to be a bother.","TWN":"所以媽媽一個人在花園裡把我養大了。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"저희 둘만 두고 떠난 관리자 씨를 원망한 적도 있지만…","JPN":"私たち2人を置いて行った管理者さんを恨んだこともありましたけど……","ENG":"There were times when I hated Mr. Administrator for leaving Mother and me behind, but...","TWN":"雖然曾經恨過拋下媽媽離開的管理者先生……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"지금은 이해해요. 세상을 지키는 건 정말 바쁜 일이니까요.","JPN":"今は理解します。世の中を守るのはとても忙しい仕事ですから。","ENG":"Now I understand. Protecting the world is an incredibly busy task.","TWN":"但現在我理解了，守護世界確實是件非常忙碌的事。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그치만 이젠 저도 다 컸으니까. 그 사람한테 뭔가 도움이 되고 싶어서 왔어요. 짐이 되지 않도록 열심히 할게요.","JPN":"それに私、もう大きくなりました。管理者さんのために何か手助けをしたいと思ってここに来たんです。足手まといにならないように、頑張りますから！","ENG":"Now I'm all grown up and want to be of some help to Mr. Administrator. That's why I came here.","TWN":"我也想為這樣的管理者先生提供一些幫助，所以我才來到這裡。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};